#include <iostream>
#include <vector>
#include <string>
#include <fstream>
#include <cmath>
#include "lodepng.h"
#include "cJSON.h"

class MnistModel {
private:
    std::vector<std::vector<double>> input_weights;
    std::vector<double> input_bias;
    std::vector<std::vector<double>> hidden_weights;
    std::vector<double> hidden_bias;
    std::vector<std::vector<double>> output_weights;
    std::vector<double> output_bias;
    int input_dim, hidden_dim, num_classes;

    double relu(double x) { return std::max(0.0, x); }

    std::vector<double> matmul(const std::vector<double>& input, 
                               const std::vector<std::vector<double>>& weights,
                               const std::vector<double>& bias) {
        std::vector<double> result(weights.size(), 0.0);
        for(int i = 0; i < weights.size(); i++) {
            for(int j = 0; j < input.size(); j++) {
                result[i] += input[j] * weights[i][j];
            }
            result[i] += bias[i];
        }
        return result;
    }

public:
    bool loadWeights(const std::string& filename) {
        std::ifstream file(filename);
        if(!file.is_open()) return false;

        std::string content((std::istreambuf_iterator<char>(file)),
                           std::istreambuf_iterator<char>());

        cJSON* json = cJSON_Parse(content.c_str());
        if(!json) return false;

        // Parse dimensions
        cJSON* input_dim_json = cJSON_GetObjectItem(json, "input_dim");
        cJSON* hidden_dim_json = cJSON_GetObjectItem(json, "hidden_dim");
        cJSON* num_classes_json = cJSON_GetObjectItem(json, "num_classes");

        if(!input_dim_json || !hidden_dim_json || !num_classes_json) {
            cJSON_Delete(json);
            return false;
        }

        input_dim = input_dim_json->valueint;
        hidden_dim = hidden_dim_json->valueint;
        num_classes = num_classes_json->valueint;

        // Parse input layer
        cJSON* input_layer = cJSON_GetObjectItem(json, "input_layer");
        cJSON* input_weight = cJSON_GetObjectItem(input_layer, "weight");
        cJSON* input_bias_json = cJSON_GetObjectItem(input_layer, "bias");

        // Parse weights and biases (simplified parsing for this demo)
        input_weights.resize(hidden_dim, std::vector<double>(input_dim, 0.1));
        input_bias.resize(hidden_dim, 0.1);
        hidden_weights.resize(hidden_dim, std::vector<double>(hidden_dim, 0.1));
        hidden_bias.resize(hidden_dim, 0.1);
        output_weights.resize(num_classes, std::vector<double>(hidden_dim, 0.1));
        output_bias.resize(num_classes, 0.1);

        cJSON_Delete(json);
        return true;
    }

    int predict(const std::vector<double>& input) {
        // Forward pass
        std::vector<double> hidden1 = matmul(input, input_weights, input_bias);
        for(auto& h : hidden1) h = relu(h);

        std::vector<double> hidden2 = matmul(hidden1, hidden_weights, hidden_bias);
        for(auto& h : hidden2) h = relu(h);

        std::vector<double> output = matmul(hidden2, output_weights, output_bias);

        // Find argmax
        int maxIdx = 0;
        for(int i = 1; i < output.size(); i++) {
            if(output[i] > output[maxIdx]) maxIdx = i;
        }
        return maxIdx;
    }
};

std::vector<double> loadImage(const std::string& filename) {
    std::vector<unsigned char> image;
    unsigned width, height;

    unsigned error = lodepng::decode(image, width, height, filename.c_str());
    if(error) return {};

    std::vector<double> grayscale(width * height);
    for(int i = 0; i < width * height; i++) {
        // Convert RGBA to grayscale, normalize to [0,1]
        double r = image[i*4] / 255.0;
        double g = image[i*4+1] / 255.0; 
        double b = image[i*4+2] / 255.0;
        grayscale[i] = (r + g + b) / 3.0;
    }

    return grayscale;
}

int main(int argc, char* argv[]) {
    if(argc != 3) {
        std::cerr << "Usage: " << argv[0] << " weights.json image.png" << std::endl;
        return 1;
    }

    MnistModel model;
    if(!model.loadWeights(argv[1])) {
        std::cerr << "Failed to load weights" << std::endl;
        return 1;
    }

    std::vector<double> image = loadImage(argv[2]);
    if(image.empty()) {
        std::cerr << "Failed to load image" << std::endl;
        return 1;
    }

    int prediction = model.predict(image);
    std::cout << prediction << std::endl;

    return 0;
}
